function findDuplicateChars(str: string): string[] {
  const freq = new Map<string, number>()

  for (const char of str) {
    freq.set(char, (freq.get(char) ?? 0) + 1)
  }

  return [...freq.entries()]
    .filter(([, count]) => count > 1)
    .map(([char]) => char)
}

